import React, { useState, useEffect } from 'react';
import axios from 'axios';

function PaymentCenter() {
  const [payments, setPayments] = useState([]);
  const [showPaymentForm, setShowPaymentForm] = useState(false);
  const [formData, setFormData] = useState({
    initiatorAccountId: '',
    beneficiaryIban: '',
    beneficiaryName: '',
    amount: 0,
    currency: 'EUR',
    paymentType: 'SEPA_SCT',
    remittanceInformation: '',
  });

  useEffect(() => {
    fetchPayments();
  }, []);

  const fetchPayments = async () => {
    try {
      // Mock data - replace with API call
      const mockPayments = [
        {
          paymentId: 'PAY001',
          initiatorAccountId: 'ACC001',
          beneficiaryIban: 'DE89370400440532013000',
          beneficiaryName: 'John Doe',
          amount: 500.00,
          currency: 'EUR',
          paymentType: 'SEPA_SCT',
          paymentStatus: 'ACCEPTED',
          createdAt: '2024-03-10T09:15:00',
        },
        {
          paymentId: 'PAY002',
          initiatorAccountId: 'ACC001',
          beneficiaryIban: 'CZ2020100000000656430200',
          beneficiaryName: 'Jane Smith',
          amount: 1200.00,
          currency: 'EUR',
          paymentType: 'SEPA_SCT',
          paymentStatus: 'PENDING',
          createdAt: '2024-03-11T14:30:00',
        },
      ];
      setPayments(mockPayments);
    } catch (error) {
      console.error('Error fetching payments:', error);
    }
  };

  const handleInitiatePayment = async (e) => {
    e.preventDefault();
    try {
      // TODO: Call API Gateway POST /api/payments
      console.log('Initiating payment:', formData);
      setShowPaymentForm(false);
      setFormData({
        initiatorAccountId: '',
        beneficiaryIban: '',
        beneficiaryName: '',
        amount: 0,
        currency: 'EUR',
        paymentType: 'SEPA_SCT',
        remittanceInformation: '',
      });
      // fetchPayments();
    } catch (error) {
      console.error('Error initiating payment:', error);
    }
  };

  const handleApprovePayment = async (paymentId) => {
    try {
      // TODO: Call API Gateway POST /api/payments/{paymentId}/approve
      console.log('Approving payment:', paymentId);
      // fetchPayments();
    } catch (error) {
      console.error('Error approving payment:', error);
    }
  };

  return (
    <div>
      <div className="card">
        <h3>💰 Payment Center</h3>
        <button className="btn-primary" onClick={() => setShowPaymentForm(!showPaymentForm)}>
          {showPaymentForm ? '✖ Cancel' : '➕ Initiate Payment'}
        </button>

        {showPaymentForm && (
          <form onSubmit={handleInitiatePayment} style={{ marginTop: '20px' }}>
            <div className="form-group">
              <label>Initiator Account</label>
              <input
                type="text"
                value={formData.initiatorAccountId}
                onChange={(e) =>
                  setFormData({ ...formData, initiatorAccountId: e.target.value })
                }
                required
              />
            </div>
            <div className="form-group">
              <label>Beneficiary IBAN</label>
              <input
                type="text"
                value={formData.beneficiaryIban}
                onChange={(e) =>
                  setFormData({ ...formData, beneficiaryIban: e.target.value })
                }
                required
              />
            </div>
            <div className="form-group">
              <label>Beneficiary Name</label>
              <input
                type="text"
                value={formData.beneficiaryName}
                onChange={(e) =>
                  setFormData({ ...formData, beneficiaryName: e.target.value })
                }
                required
              />
            </div>
            <div className="form-group">
              <label>Amount</label>
              <input
                type="number"
                step="0.01"
                value={formData.amount}
                onChange={(e) =>
                  setFormData({ ...formData, amount: parseFloat(e.target.value) })
                }
                required
              />
            </div>
            <div className="form-group">
              <label>Payment Type</label>
              <select
                value={formData.paymentType}
                onChange={(e) =>
                  setFormData({ ...formData, paymentType: e.target.value })
                }
              >
                <option>SEPA_SCT</option>
                <option>SEPA_SDD</option>
                <option>SWIFT</option>
                <option>INSTANT</option>
              </select>
            </div>
            <div className="form-group">
              <label>Remittance Information</label>
              <input
                type="text"
                value={formData.remittanceInformation}
                onChange={(e) =>
                  setFormData({ ...formData, remittanceInformation: e.target.value })
                }
              />
            </div>
            <button type="submit" className="btn-primary">
              Initiate Payment
            </button>
          </form>
        )}
      </div>

      <div className="card" style={{ marginTop: '20px' }}>
        <h3>📋 Recent Payments</h3>
        <table className="table">
          <thead>
            <tr>
              <th>Payment ID</th>
              <th>Beneficiary</th>
              <th>Amount</th>
              <th>Type</th>
              <th>Status</th>
              <th>Date</th>
              <th>Action</th>
            </tr>
          </thead>
          <tbody>
            {payments.map((payment) => (
              <tr key={payment.paymentId}>
                <td>{payment.paymentId}</td>
                <td>{payment.beneficiaryName}</td>
                <td>€{payment.amount.toFixed(2)}</td>
                <td>{payment.paymentType}</td>
                <td>
                  <span
                    style={{
                      color: payment.paymentStatus === 'ACCEPTED' ? 'green' : 'orange',
                    }}
                  >
                    {payment.paymentStatus}
                  </span>
                </td>
                <td>{new Date(payment.createdAt).toLocaleDateString()}</td>
                <td>
                  {payment.paymentStatus === 'PENDING' && (
                    <button
                      onClick={() => handleApprovePayment(payment.paymentId)}
                      style={{
                        padding: '6px 12px',
                        background: '#667eea',
                        color: 'white',
                        border: 'none',
                        borderRadius: '4px',
                        cursor: 'pointer',
                      }}
                    >
                      Approve
                    </button>
                  )}
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
}

export default PaymentCenter;
